@app.route("/auth/nonce", methods=["POST", "OPTIONS"])
def auth_nonce():
    if request.method == "OPTIONS":
        return _cors(jsonify({"ok": True}))

    _clean_expired_nonces()
    data = request.get_json(silent=True) or {}
    address = (data.get("address") or "").strip()

    if not address or not _is_address(address):
        return jsonify({"ok": False, "error": "Invalid address"}), 400

    addr = _to_checksum(address)
    nonce = _new_nonce(addr)
    issued_at = _now()

    NONCES[nonce] = {"address": addr, "issued_at": issued_at, "used": False}

    statement = data.get("statement") or "Sign in to authenticate."
    domain = data.get("domain") or request.host.split(":")[0]
    uri = data.get("uri") or f"http://{request.host}"
    version = str(data.get("version") or "1")

    message = (
        f"{domain} wants you to sign in with your Ethereum account:\n"
        f"{addr}\n\n"
        f"{statement}\n\n"
        f"URI: {uri}\n"
        f"Version: {version}\n"
        f"Chain ID: {CHAIN_ID}\n"
        f"Nonce: {nonce}\n"
        f"Issued At: {time.strftime('%Y-%m-%dT%H:%M:%SZ', time.gmtime(issued_at))}"
    )

    return jsonify({
        "ok": True,
        "address": addr,
        "nonce": nonce,
        "issued_at": issued_at,
        "expires_in": NONCE_TTL_SECONDS,
        "message": message,
        "chain_id": CHAIN_ID,
    })

@app.route("/auth/verify", methods=["POST", "OPTIONS"])
def auth_verify():
    if request.method == "OPTIONS":
        return _cors(jsonify({"ok": True}))

    _clean_expired_nonces()
    data = request.get_json(silent=True) or {}

    address = (data.get("address") or "").strip()
    message = data.get("message") or ""
    signature = (data.get("signature") or "").strip()
    nonce = (data.get("nonce") or "").strip()

    if not address or not _is_address(address):
        return jsonify({"ok": False, "error": "Invalid address"}), 400
    if not message or not isinstance(message, str):
        return jsonify({"ok": False, "error": "Invalid message"}), 400
    if not signature:
        return jsonify({"ok": False, "error": "Missing signature"}), 400
    if not nonce:
        return jsonify({"ok": False, "error": "Missing nonce"}), 400

    addr = _to_checksum(address)
    entry = NONCES.get(nonce)
    if not entry:
        return jsonify({"ok": False, "error": "Unknown nonce"}), 400
    if entry.get("used"):
        return jsonify({"ok": False, "error": "Nonce already used"}), 400
    if _now() - int(entry.get("issued_at", 0)) > NONCE_TTL_SECONDS:
        NONCES.pop(nonce, None)
        return jsonify({"ok": False, "error": "Nonce expired"}), 400
    if _to_checksum(entry.get("address")) != addr:
        return jsonify({"ok": False, "error": "Nonce does not match address"}), 400
    if f"Nonce: {nonce}" not in message:
        return jsonify({"ok": False, "error": "Message does not contain provided nonce"}), 400

    try:
        recovered = _recover_address(message, signature)
        recovered = _to_checksum(recovered)
    except Exception:
        return jsonify({"ok": False, "error": "Signature recovery failed"}), 400

    if recovered != addr:
        return jsonify({"ok": False, "error": "Signature does not match address", "recovered": recovered}), 401

    entry["used"] = True

    iat = _now()
    exp = iat + TOKEN_TTL_SECONDS
    token = _sign_token({"sub": addr, "iat": iat, "exp": exp})

    return jsonify({
        "ok": True,
        "address": addr,
        "recovered": recovered,
        "token": token,
        "token_type": "Bearer",
        "expires_in": TOKEN_TTL_SECONDS,
    })

@app.route("/me", methods=["GET", "OPTIONS"])
def me():
    if request.method == "OPTIONS":
        return _cors(jsonify({"ok": True}))

    auth = request.headers.get("Authorization", "")
    if not auth.startswith("Bearer "):
        return jsonify({"ok": False, "error": "Missing Bearer token"}), 401

    token = auth[len("Bearer "):].strip()
    ok, payload = _verify_token(token)
    if not ok or not payload:
        return jsonify({"ok": False, "error": "Invalid token"}), 401

    return jsonify({"ok": True, "address": payload.get("sub"), "iat": payload.get("iat"), "exp": payload.get("exp")})

